import { useEffect, useState } from "react";
import api from "../api/api";

export default function SystemStats() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
  setTimeout(() => {
    setStats({
      uptime: 240,
      capture: { kernel_packets: 1024 },
      flow: { tcp: 12 },
      detect: { alert: 5, alert_queue_overflow: 1 }
    });
    setLoading(false);
  }, 500);
}, []);


  if (loading) return <p className="text-center text-gray-500">Ładowanie statystyk systemu...</p>;
  if (!stats) return <p className="text-center text-red-500">Nie udało się załadować statystyk.</p>;

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-white rounded-xl shadow-md">
      <StatBox label="Uptime (s)" value={stats.uptime} />
      <StatBox label="Pakiety z jądra" value={stats.capture?.kernel_packets ?? 0} />
      <StatBox label="Sesje TCP" value={stats.flow?.tcp ?? 0} />
      <StatBox label="Liczba alertów" value={stats.detect?.alert ?? 0} />
      <StatBox label="Overflow kolejki alertów" value={stats.detect?.alert_queue_overflow ?? 0} />
    </div>
  );
}

function StatBox({ label, value }) {
  return (
    <div className="p-4 bg-gray-50 rounded border">
      <h3 className="text-lg font-semibold">{label}</h3>
      <p className="text-2xl text-blue-600 mt-2">{value}</p>
    </div>
  );
}
